178		public async getStyleIdsInDateRange({
179			startDate,
180			endDate,
181		}: {
182			startDate: string;
183			endDate: string;
184		}): Promise<IProductAnnualSalesBase[]> {
185			const startYearStr = startDate.split('-')[0];
186			const endYearStr = endDate.split('-')[0];
187	
188			if (!startYearStr || !endYearStr) {
189				throw new Error(`Invalid date format: startDate=${startDate}, endDate=${endDate}`);
190			}
191	
192			const startYear = parseInt(startYearStr, 10);
193			const endYear = parseInt(endYearStr, 10);
194	
195			this.logger.log('Fetching style IDs from year range', { startYear, endYear });
196			return await this.productAnnualSalesService.findByYearRange({ startYear, endYear });
197		}
