359		@LogExecution({
360			paramFormatter: ([params]: [
361				{
362					results: CompleteForecastResult[];
363					startDate: string;
364					endDate: string;
365					forecastDays: number;
366				},
367			]) => ({
368				resultCount: params.results.length,
369				startDate: params.startDate,
370				endDate: params.endDate,
371				forecastDays: params.forecastDays,
372			}),
373			responseFormatter: () => ({ completed: true }),
374		})
375		public async saveBatchResults({
376			results,
377			startDate,
378			endDate,
379			forecastDays,
380		}: {
381			results: CompleteForecastResult[];
382			startDate: string;
383			endDate: string;
384			forecastDays: number;
385		}): Promise<void> {
386			if (results.length === 0) return;
387	
388			try {
389				const dbPredictions: ITrendingProductsCreate[] = results
390					.map((result) => {
391						let predictedOrders = result.predicted_orders;
392						let actualForecastDays = forecastDays;
393	
394						if (forecastDays === 9 && predictedOrders.length === 9) {
395							predictedOrders = predictedOrders.slice(-7);
396							actualForecastDays = 7;
397						}
398	
399						const totalPredictedOrders = predictedOrders.reduce(
400							(sum, value) => sum + value,
401							0,
402						);
403	
404						return {
405							style_id: result.style_id,
406							predicted_orders: predictedOrders,
407							total_predicted_orders: totalPredictedOrders,
408							trend_score: result.trend_score,
409							trending_reason: result.trending_reason,
410							forecast_start_date: startDate,
411							forecast_end_date: endDate,
412							forecast_days: actualForecastDays,
413						};
414					})
415					.filter(
416						(data) =>
417							typeof data.trend_score === 'number' && !Number.isNaN(data.trend_score),
418					);
419	
420				await this.forecastedTrendingProductsService.saveBatchPredictions({
421					predictions: dbPredictions,
422				});
423			} catch (error) {
424				this.logger.error(
425					`Failed to save batch predictions to database: ${(error as Error).message}`,
426					(error as Error).stack,
427				);
428			}
429		}
430	
431		private calculateSeasonalComponent({
432			values,
433			period,
434			harmonics,
435		}: {
436			values: number[];
437			period: number;
438			harmonics: number;
439		}): number[] {
440			const n = values.length;
441			if (n < period) {
442				return new Array(n).fill(0) as number[];
443			}
444	
445			try {
446				const coefficients = MathematicalFunctions.fourierCoefficients({
447					values,
448					period,
449					harmonics,
450					precision: null,
451				});
452	
453				const seasonal = MathematicalFunctions.reconstructFourierSeries({
454					period,
455					harmonics,
456					a: coefficients.a,
457					b: coefficients.b,
458					length: n,
459				});
460	
461				return seasonal;
462			} catch (error) {
463				this.logger.error(
464					`Error extending seasonal component: ${(error as Error).message}`,
465					(error as Error).stack,
466				);
467				return values.map((_, index) => {
468					const cyclePosition = index % Math.max(1, Math.floor(period));
469					const seasonalIndex = Math.min(cyclePosition, values.length - 1);
470					return values[seasonalIndex] ? values[seasonalIndex] * 0.1 : 0;
471				});
472			}
473		}
474	
475		private calculateTrendComponent({
476			values,
477			changePoints,
478			startDate,
479			endDate,
480		}: {
481			values: number[];
482			changePoints: number[];
483			startDate: string;
484			endDate: string;
485		}): number[] {
486			const n = values.length;
487			if (n === 0) return [];
488	
489			const dates = this.generateDateRange({ startDate, endDate, count: n });
490	
491			if (changePoints.length === 0) {
492				return MathematicalFunctions.calculateTrend({ values, dates });
493			}
494	
495			const trend = new Array(n).fill(0) as number[];
496			const segments = [0, ...changePoints, n];
497	
498			for (let i = 0; i < segments.length - 1; i++) {
499				const start = segments[i] as unknown as number;
500				const end = segments[i + 1] as unknown as number;
501				const segmentValues = values.slice(start, end);
502				const segmentDates = dates.slice(start, end);
503	
504				if (segmentValues.length > 1) {
505					const segmentTrend = MathematicalFunctions.calculateTrend({
506						values: segmentValues,
507						dates: segmentDates,
508					});
509	
510					for (let j = 0; j < segmentTrend.length; j++) {
511						trend[start + j] = segmentTrend[j] as unknown as number;
512					}
513				} else if (segmentValues.length === 1) {
514					trend[start] = segmentValues[0] as unknown as number;
