661		private extendSeasonalComponent({
662			component,
663			period,
664			harmonics,
665			historicalLength,
666			forecastDates,
667			endDate,
668		}: {
669			component: number[];
670			period: number;
671			harmonics: number;
672			historicalLength: number;
673			forecastDates: string[];
674			endDate: string;
675		}): number[] {
676			if (component.length === 0) return Array(forecastDates.length).fill(0) as number[];
677	
678			try {
679				const coefficients = MathematicalFunctions.fourierCoefficients({
680					values: component,
681					period,
682					harmonics,
683					precision: null,
684				});
685	
686				const forecastValues: number[] = [];
687				const endDateObj = new Date(endDate);
688	
689				for (const forecastDate of forecastDates) {
690					const forecastDateObj = new Date(forecastDate);
691	
692					const daysDiff = Math.floor(
693						(forecastDateObj.getTime() - endDateObj.getTime()) / (1000 * 60 * 60 * 24),
694					);
695	
696					const cyclePosition = (historicalLength + daysDiff) % period;
697					const singlePointSeries = MathematicalFunctions.reconstructFourierSeries({
698						period,
699						harmonics,
700						a: coefficients.a,
701						b: coefficients.b,
702						length: Math.ceil(cyclePosition) + 1,
703						a0: 0,
704					});
705	
706					const seasonalValue = singlePointSeries[Math.floor(cyclePosition)] ?? 0;
707					forecastValues.push(seasonalValue);
708				}
709	
710				return forecastValues;
711			} catch (error) {
712				this.logger.error(
713					`Error extending seasonal component: ${(error as Error).message}`,
714					(error as Error).stack,
715				);
716				return forecastDates.map((forecastDate) => {
717					const endDateObj = new Date(endDate);
718					const forecastDateObj = new Date(forecastDate);
719					const daysDiff = Math.floor(
720						(forecastDateObj.getTime() - endDateObj.getTime()) / (1000 * 60 * 60 * 24),
721					);
722					const flooredPeriod = Math.max(1, Math.floor(period));
723					const cyclePosition = (historicalLength + daysDiff) % flooredPeriod;
724					const historicalIndex = Math.min(cyclePosition, component.length - 1);
725					return component[historicalIndex] ?? 0;
726				});
727			}
728		}
