730		private extendTrendComponent({
731			trendComponent,
732			forecastDays,
733		}: {
734			trendComponent: number[];
735			forecastDays: number;
736		}): number[] {
737			if (trendComponent.length < 2) return Array(forecastDays).fill(0) as number[];
738	
739			const recentTrendPoints = Math.min(30, trendComponent.length);
740			const recentTrend = trendComponent.slice(-recentTrendPoints);
741	
742			const x = Array.from({ length: recentTrend.length }, (_, i) => i);
743			const regression = MathematicalFunctions.linearRegression({ x, y: recentTrend });
744	
745			const lastValue = trendComponent[trendComponent.length - 1] ?? 0;
746			const trendSlope = regression.slope;
747	
748			return Array(forecastDays)
749				.fill(0)
750				.map((_, i) => {
751					const decay = Math.exp(-0.02 * i);
752					return lastValue + trendSlope * (i + 1) * decay;
753				});
754		}
755	
756		private extendResidualsComponent({
757			smoothedResidualsArr,
758			forecastDays,
759			endDate,
760		}: {
761			smoothedResidualsArr: number[];
762			forecastDays: number;
763			endDate: string;
764		}): number[] {
765			if (smoothedResidualsArr.length === 0 || forecastDays <= 0) {
766				return Array(forecastDays).fill(0) as number[];
767			}
768	
769			const twoWeeksLength = 7;
770			const trendLength = Math.min(twoWeeksLength, smoothedResidualsArr.length);
771			const recentResiduals = smoothedResidualsArr.slice(-trendLength);
772	
773			const endDateObj = new Date(endDate);
774			const dates = recentResiduals.map((_, i) => {
775				const date = new Date(endDateObj);
776				date.setDate(endDateObj.getDate() - (trendLength - i - 1));
777				const dateArr = date.toISOString().split('T') as [string, string];
778				return dateArr[0];
779			});
780	
781			const trendValues = MathematicalFunctions.calculateTrend({
782				values: recentResiduals,
783				dates,
784			});
785	
786			if (trendValues.length === 0) {
787				return Array(forecastDays).fill(0) as number[];
788			}
789	
790			const x = Array.from({ length: recentResiduals.length }, (_, i) => i);
791			const regression = MathematicalFunctions.linearRegression({ x, y: recentResiduals });
792	
793			const lastIndex = recentResiduals.length - 1;
794			return Array(forecastDays)
795				.fill(0)
796				.map((_, i) => {
797					return regression.slope * (lastIndex + i + 1) + regression.intercept;
798				});
799		}
