810		private generateFutureDates({
811			endDate,
812			forecastDays,
813		}: {
814			endDate: string;
815			forecastDays: number;
816		}): string[] {
817			const dates: string[] = [];
818			const startDate = new Date(endDate);
819	
820			for (let i = 1; i <= forecastDays; i++) {
821				const futureDate = new Date(startDate);
822				futureDate.setDate(startDate.getDate() + i);
823				const dateArr = futureDate.toISOString().split('T') as [string, string];
824				dates.push(dateArr[0]);
825			}
826	
827			return dates;
828		}
