830		private calculateTrendingReason({
831			comprehensiveForecast,
832			historicalOrders,
833			trendComponent,
834		}: {
835			comprehensiveForecast: {
836				forecastValues: number[];
837				forecastDates: string[];
838				components: {
839					yearly: number[];
840					monthly: number[];
841					weekly: number[];
842					quarterly: number[];
843					trend: number[];
844					residuals: number[];
845				};
846			};
847			historicalOrders: number[];
848			trendComponent: number[];
849		}): { trendingReason: string; growthRate: number } {
850			if (
851				historicalOrders.length === 0 ||
852				comprehensiveForecast.forecastValues.length === 0
853			) {
854				return { trendingReason: 'Stable pattern', growthRate: 0 };
855			}
856	
857			const historicalAvg =
858				historicalOrders.reduce((sum, val) => sum + val, 0) / historicalOrders.length;
859			const forecastAvg =
860				comprehensiveForecast.forecastValues.reduce((sum, val) => sum + val, 0) /
861				comprehensiveForecast.forecastValues.length;
862	
863			const growthRate =
864				historicalAvg > 0 ? (forecastAvg - historicalAvg) / historicalAvg : 0;
865	
866			const trendSlope = this.calculateTrendSlope({ trendComponent });
867	
868			if (growthRate > 0.2 || forecastAvg > historicalAvg * 1.2) {
869				return { trendingReason: 'Strong growth forecast', growthRate };
870			} else if (growthRate > 0.1 || forecastAvg > historicalAvg * 1.1) {
871				return { trendingReason: 'Moderate growth forecast', growthRate };
872			} else if (growthRate > 0 || trendSlope >= 0.05) {
873				return { trendingReason: 'Positive trend detected', growthRate };
874			} else {
875				return { trendingReason: 'Stable pattern', growthRate };
876			}
877		}
878	
879		private calculateTrendSlope({ trendComponent }: { trendComponent: number[] }): number {
880			if (trendComponent.length < 2) return 0;
881	
882			const recentPoints = Math.min(14, trendComponent.length);
883			const recentTrend = trendComponent.slice(-recentPoints);
884	
885			const x = Array.from({ length: recentTrend.length }, (_, i) => i);
886			const regression = MathematicalFunctions.linearRegression({ x, y: recentTrend });
887	
888			return regression.slope;
889		}
890	}
